interface StatsCardProps {
  title: string;
  value: string | number;
  change: {
    value: string;
    trend: 'up' | 'down';
    color: 'green' | 'red' | 'orange';
  };
  icon: string;
  iconColor: string;
}

export default function StatsCard({ title, value, change, icon, iconColor }: StatsCardProps) {
  const getTrendIcon = (trend: 'up' | 'down') => {
    return trend === 'up' ? 'fas fa-arrow-up' : 'fas fa-arrow-down';
  };

  const getTrendColor = (color: 'green' | 'red' | 'orange') => {
    switch (color) {
      case 'green':
        return 'text-green-600';
      case 'red':
        return 'text-red-600';
      case 'orange':
        return 'text-orange-600';
      default:
        return 'text-gray-600';
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200" data-testid="stats-card">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm font-medium text-gray-600">{title}</p>
          <p className="text-2xl font-bold text-gray-900 mt-2" data-testid="stats-value">
            {typeof value === 'number' ? value.toLocaleString() : value}
          </p>
          <p className={`text-sm mt-1 ${getTrendColor(change.color)}`}>
            <i className={`${getTrendIcon(change.trend)} text-xs mr-1`}></i>
            {change.value}
          </p>
        </div>
        <div className={`p-3 bg-gray-100 rounded-lg`}>
          <i className={`${icon} ${iconColor} text-lg`}></i>
        </div>
      </div>
    </div>
  );
}

client/src/lib/types.ts.content:
export interface User {
  id: string;
  username: string;
  email: string;
  firstName?: string;
  lastName?: string;
  profileImageUrl?: string;
  reputationScore: number;
  role: 'user' | 'moderator' | 'admin';
  isActive: boolean;
  isBanned: boolean;
  createdAt: string;
  updatedAt: string;
}

export interface Post {
  id: string;
  userId: string;
  content: string;
  contentType: 'text' | 'image' | 'video';
  imageUrl?: string;
  videoUrl?: string;
  language: string;
  isModerated: boolean;
  moderationStatus: 'pending' | 'approved' | 'rejected' | 'flagged';
  moderationReason?: string;
  aiConfidence?: number;
  aiFlags?: string[];
  createdAt: string;
  updatedAt: string;
  user?: User;
  commentCount?: number;
}

export interface Comment {
  id: string;
  postId: string;
  userId: string;
  content: string;
  language: string;
  isModerated: boolean;
  moderationStatus: 'pending' | 'approved' | 'rejected' | 'flagged';
  moderationReason?: string;
  aiConfidence?: number;
  aiFlags?: string[];
  createdAt: string;
  updatedAt: string;
  user?: User;
  post?: Post;
}

export interface ModerationAction {
  id: string;
  contentId: string;
  contentType: 'post' | 'comment';
  moderatorId?: string;
  action: 'approve' | 'reject' | 'flag' | 'ban_user';
  reason?: string;
  isAutomatic: boolean;
  aiModel?: string;
  confidence?: number;
  details?: any;
  createdAt: string;
  content?: Post | Comment;
  user?: User;
}

export interface AIModelStatus {
  id: string;
  modelName: string;
  modelType: 'text' | 'image' | 'video';
  status: 'active' | 'loading' | 'error' | 'disabled';
  version?: string;
  lastHealthCheck: string;
  errorMessage?: string;
  configuration?: any;
}

export interface ContentStats {
  totalProcessed: number;
  totalFlagged: number;
  totalBlocked: number;
  activeUsers: number;
}

export interface ReputationInsights {
  distribution: Array<{
    range: string;
    label: string;
    count: number;
  }>;
  lowReputationUsers: Array<User & { recentViolations: number }>;
  averageScore: number;
}

export interface PendingContent {
  posts: Post[];
  comments: Comment[];
}

export interface DashboardAnalytics {
  stats: ContentStats;
  recentActions: ModerationAction[];
  aiModels: AIModelStatus[];
  reputationInsights: ReputationInsights;
  languageDistribution: Record<string, number>;
  contentTypeDistribution: Record<string, number>;
  detectionInsights: Array<{
    type: string;
    count: number;
    percentage: number;
  }>;
}

